import React, { useState, useCallback } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { FaEye, FaEyeSlash } from 'react-icons/fa';
import { Cpu, Terminal, ShieldCheck, Lock } from 'lucide-react';
import toast from 'react-hot-toast';

const FormField = ({ label, icon: Icon, children }) => (
  <div className="flex flex-col gap-2 relative">
    <label className="text-[10px] font-bold text-[var(--accent-primary)] uppercase tracking-widest ml-1 flex items-center gap-2">
      <Icon size={12} /> {label}
    </label>
    {children}
  </div>
);

const LoginPage = () => {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);

  const { login } = useAuth();
  const { isDarkMode } = useTheme(); 
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleLogin = useCallback(async (e) => {
    e.preventDefault();
    const { email, password } = formData;

    if (!email || !password) return toast.error('FIELDS_REQUIRED');
    
    const tid = toast.loading('SYNCHRONIZING_NODE...');
    setLoading(true);
    
    try {
      await login(email, password);
      toast.success('ACCESS_GRANTED', { id: tid });
      navigate('/dashboard');
    } catch (err) {
      toast.error('GATE_REJECTION: INVALID_CREDENTIALS', { id: tid });
    } finally {
      setLoading(false);
    }
  }, [formData, login, navigate]);

  return (
    <div className="vault-card reveal-node relative overflow-hidden">
      <div className="animate-laser absolute inset-0 pointer-events-none" />

      <header className="flex flex-col items-center mb-10">
        <div className={`p-4 rounded-2xl mb-4 transition-all duration-500 ${
          isDarkMode ? 'bg-emerald-500/10 shadow-[0_0_20px_rgba(16,185,129,0.1)]' : 'bg-emerald-600/5'
        }`}>
          <Cpu className="text-[var(--accent-primary)] animate-pulse" size={32} />
        </div>
        <h2 className="text-2xl font-light tracking-[0.3em] uppercase text-[var(--text-primary)]">
          Access_Gate
        </h2>
        <p className="text-[10px] text-[var(--text-muted)] tracking-[0.4em] uppercase mt-2 opacity-70">
          Secure_Node_v3.2 // {isDarkMode ? 'Dark_Protocol' : 'Light_Protocol'}
        </p>
      </header>

      <form onSubmit={handleLogin} className="space-y-5">
        <FormField label="Registry_Email" icon={Terminal}>
          <input 
            name="email"
            type="email" 
            className="cyber-input" 
            placeholder="operator@finify.ai"
            value={formData.email}
            onChange={handleChange}
            autoComplete="username"
            required
          />
        </FormField>

        <FormField label="Security_Key" icon={Lock}>
          <div className="relative">
            <input 
              name="password"
              type={showPass ? "text" : "password"} 
              className="cyber-input pr-12" 
              placeholder="••••••••"
              value={formData.password}
              onChange={handleChange}
              autoComplete="current-password"
              required
            />
            <button 
              type="button" 
              onClick={() => setShowPass(!showPass)}
              className="absolute right-4 top-1/2 -translate-y-1/2 text-[var(--text-muted)] hover:text-[var(--accent-primary)] transition-colors focus:outline-none"
            >
              {showPass ? <FaEyeSlash size={16} /> : <FaEye size={16} />}
            </button>
          </div>
        </FormField>

        <button 
          type="submit" 
          disabled={loading}
          className={`cyber-btn mt-4 group relative overflow-hidden ${loading ? 'opacity-70 cursor-not-allowed' : ''}`}
        >
          {loading ? (
            <span className="flex items-center gap-2">
              <span className="w-4 h-4 border-2 border-black/30 border-t-black rounded-full animate-spin" />
              SYNCHRONIZING...
            </span>
          ) : (
            <>
              <ShieldCheck size={18} className="group-hover:rotate-12 transition-transform" />
              <span>Connect_to_Terminal</span>
            </>
          )}
        </button>
      </form>

      <footer className="mt-10 pt-6 border-t border-[var(--surface-border)] text-center">
        <p className="text-[10px] text-[var(--text-muted)] mb-3 italic">
          Identity_Not_Found?
        </p>
        <Link 
          to="/register" 
          className="text-[10px] text-[var(--accent-primary)] font-bold uppercase tracking-widest hover:tracking-[0.2em] transition-all duration-300"
        >
          Initialize_New_Identity
        </Link>
      </footer>
    </div>
  );
};

export default LoginPage;
